class SteamTradeInjector{constructor(){this.isInitialized=!1,this.pendingOrders=[],this.init()}init(){"loading"===document.readyState?document.addEventListener("DOMContentLoaded",(()=>this.setup())):this.setup()}setup(){this.isSteamSite()&&(chrome.runtime.onMessage.addListener(((e,t,s)=>{this.handleMessage(e,t,s)})),this.extractSteamSession(),this.isInitialized=!0)}isSteamSite(){return"steamcommunity.com"===window.location.hostname}handleMessage(e,t,s){switch(e.type){case"CREATE_TRADE_OFFER":return this.createTradeOffer(e.order).then((e=>s(e))).catch((e=>s({success:!1,error:e.message}))),!0;case"GET_STEAM_SESSION":s({success:!0,sessionData:this.getSteamSessionData()});break;default:s({success:!1,error:"Unknown message type"})}}async createTradeOffer(e){try{const t=this.getSteamSessionData();if(!t.sessionId)throw new Error("Не удалось получить Steam session");const s=this.prepareTradeData(e,t),r=await this.sendTradeOffer(s);return chrome.runtime.sendMessage({type:"TRADE_OFFER_CREATED",orderId:e.id,tradeOfferId:r}),{success:!0,tradeOfferId:r,message:`Трейд-оффер #${r} отправлен покупателю`}}catch(t){throw chrome.runtime.sendMessage({type:"TRADE_OFFER_ERROR",orderId:e.id,error:t.message}),t}}getSteamSessionData(){const e={sessionId:this.extractSessionId(),steamId:this.extractSteamId(),csrfToken:this.extractCSRFToken()};return console.log("🔑 Steam session данные:",e),e}extractSessionId(){const e=document.cookie.split(";");for(let t of e){const[e,s]=t.trim().split("=");if("sessionid"===e)return s}return window.g_sessionID?window.g_sessionID:null}extractSteamId(){if(window.g_steamID)return window.g_steamID;const e=window.location.href.match(/steamcommunity\.com\/(profiles|id)\/([^\/]+)/);return e?e[2]:null}extractCSRFToken(){const e=document.querySelector('meta[name="csrf-token"]');if(e)return e.getAttribute("content");const t=document.querySelectorAll("script");for(let e of t){const t=e.textContent.match(/sessionid['"]\s*:\s*['"]([^'"]+)['"]/);if(t)return t[1]}return null}prepareTradeData(e,t){return{sessionid:t.sessionId,partner:this.steamIdToAccountId(e.buyer.steam_id),tradeoffermessage:`Заказ #${e.id} с CS-SKINS.pro. Спасибо за покупку!`,json_tradeoffer:JSON.stringify({newversion:!0,version:2,me:{assets:e.items.map((e=>({appid:730,contextid:"2",amount:e.quantity,assetid:e.steam_asset_id}))),currency:[],ready:!1},them:{assets:[],currency:[],ready:!1}}),captcha:"",trade_offer_create_params:JSON.stringify({trade_offer_access_token:this.extractTradeToken(e.buyer.trade_url)})}}steamIdToAccountId(e){return(BigInt(e)-BigInt("76561197960265728")).toString()}extractTradeToken(e){const t=e.match(/token=([a-zA-Z0-9_-]+)/);return t?t[1]:""}async sendTradeOffer(e){try{const t=await fetch("https://steamcommunity.com/tradeoffer/new/send",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=UTF-8","X-Requested-With":"XMLHttpRequest"},body:new URLSearchParams(e),credentials:"include"});if(!t.ok)throw new Error(`HTTP ${t.status}: ${t.statusText}`);const s=await t.json();if(s.strError)throw new Error(s.strError);if(!s.tradeofferid)throw new Error("Не получен ID трейд-оффера");return s.tradeofferid}catch(e){throw console.error("❌ Ошибка отправки трейда через Steam API:",e),e}}extractSteamSession(){const e=this.getSteamSessionData();e.sessionId&&(console.log("✅ Steam session данные извлечены"),chrome.runtime.sendMessage({type:"STEAM_SESSION_EXTRACTED",sessionData:e}))}debugPageInfo(){console.log("🔍 Steam Page Debug Info:",{url:window.location.href,sessionId:this.extractSessionId(),steamId:this.extractSteamId(),csrfToken:this.extractCSRFToken(),globalVars:{g_sessionID:window.g_sessionID,g_steamID:window.g_steamID,g_rgWalletInfo:window.g_rgWalletInfo}})}}const steamInjector=new SteamTradeInjector;window.steamInjector=steamInjector;